import React, { useState, useMemo } from 'react';
import { Dialog, DialogContent, DialogHeader, DialogTitle } from '@/components/ui/dialog';
import { ScrollArea } from '@/components/ui/scroll-area';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Search } from 'lucide-react';
import ConditionsTab from './ConditionsTab';
import ChannelList from './ChannelList';
import type { Task, CreateTaskRequest, Channel, Game } from '@/types/task';
import { logger } from '@/utils/logger';
import { Users, Gamepad2, Filter, Shield, Settings } from 'lucide-react';
import { Badge } from '@/components/ui/badge';
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select';

interface TaskModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSubmit: (data: CreateTaskRequest) => Promise<void>;
  task?: Task | null;
}

const TaskModal: React.FC<TaskModalProps> = ({
  isOpen,
  onClose,
  onSubmit,
  task
}) => {
  const [activeTab, setActiveTab] = useState('channels');
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [channelSearch, setChannelSearch] = useState('');
  const [gameSearch, setGameSearch] = useState('');
  const [taskData, setTaskData] = useState<Partial<CreateTaskRequest>>({
    name: task?.name || '',
    description: task?.description || '',
    task_type: task?.task_type || 'combined',  // Set default task type
    channel_ids: task?.channel_ids || [],
    game_ids: task?.game_ids || [],
    schedule_type: task?.schedule_type || 'interval',
    schedule_value: task?.schedule_value || '3600',  // 1 hour in seconds
    storage_limit_gb: task?.storage_limit_gb || 0,   // Default to 0 instead of undefined
    retention_days: task?.retention_days || 0,       // Default to 0 instead of undefined
    auto_delete: task?.auto_delete || false,
    priority: task?.priority || 'low',
    conditions: task?.conditions || {},
    restrictions: task?.restrictions || {}
  });

  const handleSubmit = async () => {
    if (!taskData.name?.trim()) {
      return;
    }

    setIsSubmitting(true);
    try {
      const finalData: CreateTaskRequest = {
        name: taskData.name,
        description: taskData.description || '',
        task_type: taskData.task_type || 'combined',
        channel_ids: taskData.channel_ids || [],
        game_ids: taskData.game_ids || [],
        schedule_type: taskData.schedule_type || 'interval',
        schedule_value: taskData.schedule_value || '3600',
        storage_limit_gb: taskData.storage_limit_gb || 0,
        retention_days: taskData.retention_days || 0,
        auto_delete: taskData.auto_delete || false,
        priority: taskData.priority || 'low',
        conditions: taskData.conditions || {},
        restrictions: taskData.restrictions || {}
      };

      logger.debug('Submitting task data:', finalData);
      await onSubmit(finalData);
      onClose();
    } catch (error) {
      logger.error('Error saving task:', error);
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <Dialog open={isOpen} onOpenChange={onClose}>
      <DialogContent className="max-w-4xl h-[80vh] flex flex-col">
        <DialogHeader>
          <DialogTitle>
            {task ? 'Edit Task' : 'Create New Task'}
          </DialogTitle>
          <div className="flex items-center gap-4">
            <Badge variant="outline" className="flex items-center gap-1">
              <Users className="h-3 w-3"/>
              {taskData.channel_ids?.length || 0} channels
            </Badge>
            <Badge variant="outline" className="flex items-center gap-1">
              <Gamepad2 className="h-3 w-3"/>
              {taskData.game_ids?.length || 0} games
            </Badge>
          </div>
        </DialogHeader>

        <div className="space-y-4 mb-4">
          <div>
            <Label>Task Name</Label>
            <Input
              value={taskData.name || ''}
              onChange={e => handleInputChange('name', e.target.value)}
              placeholder="Enter task name"
            />
          </div>

          <div>
            <Label>Description</Label>
            <Input
              value={taskData.description || ''}
              onChange={e => handleInputChange('description', e.target.value)}
              placeholder="Enter task description (optional)"
            />
          </div>
        </div>

        <Tabs value={activeTab} onValueChange={setActiveTab} className="flex-1 flex flex-col">
          <TabsList className="w-full justify-start">
            <TabsTrigger value="channels" className="flex items-center gap-2">
              <Users className="h-4 w-4"/>
              Channels
            </TabsTrigger>
            <TabsTrigger value="games" className="flex items-center gap-2">
              <Gamepad2 className="h-4 w-4"/>
              Games
            </TabsTrigger>
            <TabsTrigger value="conditions" className="flex items-center gap-2">
              <Filter className="h-4 w-4"/>
              Conditions
            </TabsTrigger>
            <TabsTrigger value="restrictions" className="flex items-center gap-2">
              <Shield className="h-4 w-4"/>
              Restrictions
            </TabsTrigger>
            <TabsTrigger value="settings" className="flex items-center gap-2">
              <Settings className="h-4 w-4"/>
              Settings
            </TabsTrigger>
          </TabsList>

          <ScrollArea className="flex-1 overflow-hidden">
            <TabsContent value="channels" className="h-[460px] p-4">
              <div className="relative">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-muted-foreground" />
                <Input
                  placeholder="Search channels..."
                  value={channelSearch}
                  onChange={e => setChannelSearch(e.target.value)}
                  className="pl-10"
                />
              </div>

              <div className="mt-4">
                <ChannelList
                  selected={taskData.channel_ids || []}
                  onSelect={(channelId) => {
                    setTaskData(prev => {
                      const currentIds = prev.channel_ids || [];
                      const newIds = currentIds.includes(channelId)
                        ? currentIds.filter(id => id !== channelId)
                        : [...currentIds, channelId];
                      return {
                        ...prev,
                        channel_ids: newIds
                      };
                    });
                  }}
                  searchQuery={channelSearch}
                />
              </div>
            </TabsContent>

            <TabsContent value="games" className="h-[460px] p-4">
              <div className="relative">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-muted-foreground" />
                <Input
                  placeholder="Search games..."
                  value={gameSearch}
                  onChange={e => setGameSearch(e.target.value)}
                  className="pl-10"
                />
              </div>

              <div className="mt-4">
                {/* Game list will go here */}
              </div>
            </TabsContent>

            <TabsContent value="conditions" className="p-4">
              <ConditionsTab
                conditions={taskData.conditions || {}}
                onChange={conditions => handleInputChange('conditions', conditions)}
              />
            </TabsContent>

            <TabsContent value="restrictions" className="p-4">
              {/* Restrictions content */}
            </TabsContent>

            <TabsContent value="settings" className="p-4">
              <div className="grid grid-cols-2 gap-6">
                <div className="space-y-4">
                  <div className="space-y-2">
                    <Label>Schedule Type</Label>
                    <Select
                      value={taskData.schedule_type}
                      onValueChange={(value) => handleInputChange('schedule_type', value)}
                    >
                      <SelectTrigger>
                        <SelectValue placeholder="Select schedule type" />
                      </SelectTrigger>
                      <SelectContent>
                        <SelectItem value="interval">Interval</SelectItem>
                        <SelectItem value="cron">Cron</SelectItem>
                        <SelectItem value="manual">Manual</SelectItem>
                      </SelectContent>
                    </Select>
                  </div>

                  <div className="space-y-2">
                    <Label>
                      {taskData.schedule_type === 'interval' ? 'Interval (seconds)' :
                       taskData.schedule_type === 'cron' ? 'Cron Expression' :
                       'Schedule Value'}
                    </Label>
                    <Input
                      type={taskData.schedule_type === 'interval' ? 'number' : 'text'}
                      value={taskData.schedule_value}
                      onChange={e => handleInputChange('schedule_value', e.target.value)}
                      placeholder={
                        taskData.schedule_type === 'interval' ? '3600' :
                        taskData.schedule_type === 'cron' ? '0 */6 * * *' :
                        ''
                      }
                      disabled={taskData.schedule_type === 'manual'}
                    />
                  </div>
                </div>

                <div className="space-y-4">
                  <div className="space-y-2">
                    <Label>Priority Level</Label>
                    <Select
                      value={taskData.priority}
                      onValueChange={(value) => handleInputChange('priority', value)}
                    >
                      <SelectTrigger>
                        <SelectValue placeholder="Select priority" />
                      </SelectTrigger>
                      <SelectContent>
                        <SelectItem value="low">Low</SelectItem>
                        <SelectItem value="normal">Normal</SelectItem>
                        <SelectItem value="high">High</SelectItem>
                      </SelectContent>
                    </Select>
                  </div>

                  <div className="space-y-2">
                    <Label>Storage Limit (GB)</Label>
                    <Input
                      type="number"
                      value={taskData.storage_limit_gb || ''}
                      onChange={e => handleInputChange('storage_limit_gb', e.target.value ? parseInt(e.target.value) : undefined)}
                      placeholder="Optional"
                      min="0"
                    />
                  </div>

                  <div className="space-y-2">
                    <Label>Retention Days</Label>
                    <Input
                      type="number"
                      value={taskData.retention_days || ''}
                      onChange={e => handleInputChange('retention_days', e.target.value ? parseInt(e.target.value) : undefined)}
                      placeholder="Optional"
                      min="0"
                    />
                  </div>

                  <div className="space-y-2">
                    <Label className="flex items-center gap-2">
                      <input
                        type="checkbox"
                        checked={taskData.auto_delete}
                        onChange={e => handleInputChange('auto_delete', e.target.checked)}
                        className="rounded border-input h-4 w-4 text-purple-600 focus:ring-purple-500"
                      />
                      Auto-delete files after retention period
                    </Label>
                  </div>
                </div>
              </div>
            </TabsContent>
          </ScrollArea>
        </Tabs>

        <div className="flex justify-end space-x-2 mt-6">
          <Button variant="outline" onClick={onClose} type="button">
            Cancel
          </Button>
          <Button
            onClick={handleSubmit}
            disabled={isSubmitting || !taskData.name?.trim()}
            type="submit"
          >
            {isSubmitting ? 'Saving...' : 'Save Task'}
          </Button>
        </div>
      </DialogContent>
    </Dialog>
  );
};

export default TaskModal;

